        if value < prev_value:
            total -= value
        else:
            total += value
        prev_value = value
    return total

def base_convert(number, base):
    if number == 0:
        return '0'
    digits = '0123456789abcdefghijklmnopqrstuvwxyz'
    result = ''
    while number > 0:
        result = digits[number % base] + result
        number //= base
    return result

