def max_gold(M):
    if not M:
        return 0

    m, n = len(M), len(M[0])
    dp = [[0] * n for _ in range(m)]

    for col in range(n-1, -1, -1):
        for row in range(m):
            right = dp[row][col+1] if col < n-1 else 0
            right_up = dp[row-1][col+1] if row > 0 and col < n-1 else 0
            right_down = dp[row+1][col+1] if row < m-1 and col < n-1 else 0

