def rabin_karp(text, pattern):
    n, m = len(text), len(pattern)
    if m == 0:
        return True
    p_hash, t_hash = 0, 0
    h = pow(256, m-1) % 257
    for i in range(m):
        p_hash = (p_hash * 256 + ord(pattern[i])) % 257
        t_hash = (t_hash * 256 + ord(text[i])) % 257
    for i in range(n-m+1):
        if p_hash == t_hash:
            if text[i:i+m] == pattern:
                return True
        if i < n-m:
            t_hash = (256 * (t_hash - ord(text[i]) * h) + ord(text[i+m])) % 257
            if t_hash < 0:
                t_hash += 257
    return False

